import httpx
import asyncio
from typing import Any

class ApiClient:
    def __init__(self, base_url: str, max_retries: int = 3):
        self.base_url = base_url
        self.client = httpx.AsyncClient()
        self.max_retries = max_retries

    async def _request_with_retry(self, coro) -> Any:
        retries = self.max_retries
        delay = 1
        last_exc = None
        while True:
            try:
                return await coro()
            except (httpx.HTTPStatusError) as exc:
                if exc.response is not None and 500 <= exc.response.status_code < 600:
                    last_exc = exc
                else:
                    raise
            except httpx.ConnectError as exc:
                last_exc = exc
            retries -= 1
            if retries < 0:
                raise last_exc
            await asyncio.sleep(delay)
            delay *= 2

    async def get(self, endpoint: str) -> dict[str, Any]:
        async def _coro():
            response = await self.client.get(f"{self.base_url}{endpoint}")
            response.raise_for_status()
            return response.json()
        return await self._request_with_retry(_coro)

    async def post(self, endpoint: str, data: dict) -> dict[str, Any]:
        async def _coro():
            response = await self.client.post(f"{self.base_url}{endpoint}", json=data)
            response.raise_for_status()
            return response.json()
        return await self._request_with_retry(_coro)
