       |  * $BUNDLE_ID_FORMAT;
       |  * Use reverse DNS notation (e.g. "com.mycompany.myapp");
       |""".trimMargin()
private val ERR_BUNDLE_ID_WRONG_FORMAT =
    "$ERR_PREFIX $BUNDLE_ID_FORMAT"

